<template><div class="workspace-page"><section class="welcome-panel"><div><p>机构报告生产中心</p><h2>{{summary.institution?.name||'机构运营总览'}}</h2><span>机构只管理本机构报告，不可浏览用户日常测量或其他健康资料。</span></div><el-button type="primary" @click="router.push({name:'org-reports'})">进入体检报告</el-button></section><section class="metric-grid" v-loading="loading"><article v-for="m in metrics" :key="m.label" class="metric-card"><span class="metric-icon">{{m.icon}}</span><div><small>{{m.label}}</small><strong>{{m.value}}</strong><p>{{m.note}}</p></div></article></section><el-alert title="报告确认锁定后不可修改；提交时按健康身份码和姓名自动归档，归档后不可撤下。" type="info" show-icon :closable="false"/></div></template><script setup>import{computed,onMounted,ref}from"vue";import{useRouter}from"vue-router";import{fetchOrgDashboard}from"../../api/dashboards";const router=useRouter(),summary=ref({}),loading=ref(false);const metrics=computed(()=>{const c=summary.value.report_status_counts||{};return[{label:"草稿",value:c.draft||0,icon:"草",note:"可录入和修改"},{label:"已锁定",value:c.locked||0,icon:"锁",note:"等待提交"},{label:"已归档",value:c.published||0,icon:"成",note:"已向对应用户永久只读开放"}]});onMounted(async()=>{loading.value=true;try{summary.value=(await fetchOrgDashboard()).data.summary||{}}finally{loading.value=false}});</script>
